import React, { useState } from 'react';
import { 
  ChevronRight, 
  ChevronLeft, 
  UserPlus, 
  FileEdit, 
  Calendar 
} from 'lucide-react';

const FormSection = () => {
  const [activeStep, setActiveStep] = useState(0);
  const steps = [
    { title: 'Add Information', icon: UserPlus },
    { title: 'Modify Information', icon: FileEdit },
    { title: 'Calendar', icon: Calendar }
  ];

  const formFields = {
    0: [
      { label: 'First Name', type: 'text', placeholder: 'Enter your first name' },
      { label: 'Last Name', type: 'text', placeholder: 'Enter your last name' },
      { label: 'Email', type: 'email', placeholder: 'Enter your email' },
      { label: 'Phone', type: 'tel', placeholder: 'Enter your phone number' }
    ]
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-3xl mx-auto">
        {/* Progress Bar with Icons */}
        <div className="mb-8">
          <div className="flex justify-between items-center">
            {steps.map((step, idx) => (
              <div key={idx} className="flex flex-col items-center flex-1">
                <div className="relative w-full">
                  <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full">
                    <div 
                      className={`h-1 transition-all duration-500 ease-in-out ${
                        idx <= activeStep ? 'bg-blue-500' : 'bg-gray-200 dark:bg-gray-700'
                      }`}
                    />
                  </div>
                  <div 
                    className={`w-12 h-12 rounded-full flex items-center justify-center relative z-10 
                    transform transition-all duration-300 ease-in-out hover:scale-110 active:scale-95
                    ${idx <= activeStep 
                      ? 'bg-blue-500 text-white' 
                      : 'bg-gray-200 dark:bg-gray-700 text-gray-500'
                    }`}
                  >
                    <step.icon className="w-6 h-6" />
                  </div>
                </div>
                <span className="mt-2 text-sm font-medium text-gray-600 dark:text-gray-300 text-center">
                  {step.title}
                </span>
              </div>
            ))}
          </div>
        </div>

        {/* Form Card */}
        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-xl overflow-hidden
                      transform transition-all duration-500 ease-in-out opacity-100 translate-y-0">
          <div className="p-8">
            <div key={activeStep} className="space-y-6 animate-fadeIn">
              {formFields[activeStep]?.map((field, idx) => (
                <div
                  key={idx}
                  className="animate-slideIn"
                  style={{ animationDelay: `${idx * 100}ms` }}
                >
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                    {field.label}
                  </label>
                  <input
                    type={field.type}
                    placeholder={field.placeholder}
                    className="w-full px-4 py-3 rounded-lg border border-gray-200 dark:border-gray-600 
                             bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-white
                             focus:ring-2 focus:ring-blue-500 focus:border-transparent
                             transition-all duration-200 ease-in-out
                             hover:bg-gray-100 dark:hover:bg-gray-600"
                  />
                </div>
              ))}
            </div>

            {/* Navigation Buttons */}
            <div className="flex justify-between mt-8">
              <button
                className={`flex items-center px-6 py-3 rounded-lg transition-all duration-200 
                transform hover:scale-102 active:scale-98
                ${activeStep === 0
                  ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
                  : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                }`}
                onClick={() => setActiveStep(Math.max(0, activeStep - 1))}
                disabled={activeStep === 0}
              >
                <ChevronLeft className="w-5 h-5 mr-2" />
                Previous
              </button>

              <button
                className="flex items-center px-6 py-3 rounded-lg bg-blue-600 hover:bg-blue-700 
                         text-white transition-all duration-200
                         transform hover:scale-102 active:scale-98"
                onClick={() => setActiveStep(Math.min(2, activeStep + 1))}
              >
                Next
                <ChevronRight className="w-5 h-5 ml-2" />
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FormSection;
